using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Preserve EF8 discriminator property name so existing documents and
        // raw SQL queries using c.Discriminator continue to work.
        modelBuilder.Entity<Blog>().HasDiscriminator<string>("Discriminator");

        // Preserve EF8 compound id format ("Blog|1") so existing documents
        // remain accessible via FindAsync and point-reads.
        modelBuilder.Entity<Blog>().HasRootDiscriminatorInJsonId(true);

        // REMOVED: HasIndex is no longer silently ignored — it throws in EF9.
        // Cosmos DB indexing is managed via the container's indexing policy.
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

